import React, { useState, useEffect } from "react";
import axios from "axios";
import { FaKey } from "react-icons/fa";
import { useNavigate } from "react-router-dom";
import "./verifyotp.css";

const VerifyOtpPage = () => {
  const [otp, setOtp] = useState("");
  const [otpMessage, setOtpMessage] = useState("");
  const [otpError, setOtpError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const navigate = useNavigate();

  // Redirect to forgot-password if no email is stored
  useEffect(() => {
    const userEmail = localStorage.getItem("resetEmail");
    if (!userEmail) {
      navigate("/forgot-password");
    }
  }, [navigate]);

  const handleOtpVerification = async (e) => {
    e.preventDefault();
    setOtpMessage("");
    setOtpError("");

    if (!otp.trim()) {
      setOtpError("OTP is required.");
      return;
    }

    try {
      setIsSubmitting(true);
      const userEmail = localStorage.getItem("resetEmail"); 

      const response = await axios.post("http://localhost:5000/api/auth/verify-otp", {
        email: userEmail,
        otp,
      });

      if (response.data?.verified) {
        setOtpMessage("OTP verified. Redirecting...");
        localStorage.setItem("otpToken", otp);  

        setTimeout(() => {
          navigate("/reset-password");
        }, 1500);
      } else {
        setOtpError(response.data.message || "Invalid OTP.");
      }
    } catch (err) {
      setOtpError("Error verifying OTP. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="verify-otp-container">
      <img src="/assets/ODCSE Logo.png" alt="Logo" className="logo" />

      <div className="verify-otp-card">
        <h2>Verify OTP</h2>
        <p>Enter the OTP sent to your email</p>

        <form onSubmit={handleOtpVerification}>
          <div className="input-group">
            <FaKey className="icon" />
            <input
              type="text"
              placeholder="Enter OTP"
              value={otp}
              onChange={(e) => setOtp(e.target.value)}
              required
              disabled={isSubmitting}
            />
          </div>

          <button type="submit" className="verify-otp-button" disabled={isSubmitting}>
            {isSubmitting ? "Verifying..." : "Verify OTP"}
          </button>

          <div className="message-container">
            {otpMessage && <p className="success-message">{otpMessage}</p>}
            {otpError && <p className="error-message">{otpError}</p>}
          </div>
        </form>
      </div>

      <button onClick={() => navigate("/forgot-password")} className="back-button">
        Back
      </button>
    </div>
  );
};

export default VerifyOtpPage;
